        &QueryString;

declare @name nvarchar(4000)
if @nh_theo = '0' and exists(select 1 from dmtk where tk = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_tk else ten_tk2 end) from dmtk where tk = @ma
if @nh_theo = '1' and exists(select 1 from dmtk where tk = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_tk else ten_tk2 end) from dmtk where tk = @ma
if @nh_theo = '2' and exists(select 1 from dmkh where ma_kh = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_kh else ten_kh2 end) from dmkh where ma_kh = @ma
if @nh_theo = '3' and exists(select 1 from dmvv where ma_vv = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_vv else ten_vv2 end) from dmvv where ma_vv = @ma
if @nh_theo = '4' and exists(select 1 from vdmsp where ma_vt = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_vt else ten_vt2 end) from vdmsp where ma_vt = @ma
if @nh_theo = '5' and exists(select 1 from dmbp where ma_bp = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_bp else ten_bp2 end) from dmbp where ma_bp = @ma
if @nh_theo = '6' and exists(select 1 from dmdvcs where ma_dvcs = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_dvcs else ten_dvcs2 end) from dmdvcs where ma_dvcs = @ma

select 'this._itemName = ''' + replace(replace(isnull(@name, ''), '\', '\\'), '''', '\''') + ''';this._queryFilterString = ''' + replace(replace(@@queryString, '\', '\\'), '''', '\''') + ''';init$GridQuery$(this);' as message
return




    &XMLWhenReportLoading;
    &XMLWhenReportClosing;





      &DeclareCommandFilter;



        &QueryString;

declare @queryWhereClause nvarchar(4000), @queryFormClause nvarchar(4000)
select @queryFormClause = 'left join dmkh b on a.ma_kh = b.ma_kh'
select @queryWhereClause = ''
select @queryWhereClause = case
  when @nh_theo = '0' then 'a.tk_du = ''' +  replace(@ma, '''', '''''') + ''''
  when @nh_theo = '1' then 'a.tk = ''' +  replace(@ma, '''', '''''') + ''''
  when @nh_theo = '2' then 'a.ma_kh = ''' +  replace(@ma, '''', '''''') + ''''
  when @nh_theo = '3' then 'a.ma_vv = ''' +  replace(@ma, '''', '''''') + ''''
  when @nh_theo = '4' then 'a.ma_sp = ''' +  replace(@ma, '''', '''''') + ''''
  when @nh_theo = '5' then 'a.ma_bp = ''' +  replace(@ma, '''', '''''') + ''''
  else 'a.ma_dvcs = ''' +  replace(@ma, '''', '''''') + ''''
end

if @so_ct1 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct >= ''' + dbo.ff_PadL(replace(rtrim(@so_ct1), '''', ''''''), @maxLength) + ''''
if @so_ct2 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct <= ''' + dbo.ff_PadL(replace(rtrim(@so_ct2), '''', ''''''), @maxLength) + ''''

if @ma_vv <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_vv like ''' + replace(rtrim(@ma_vv), '''', '''''') + '%'''
if @ma_bp <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_bp like ''' + replace(rtrim(@ma_bp), '''', '''''') + '%'''
if @so_lsx <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_lsx like ''' + replace(rtrim(@so_lsx), '''', '''''') + '%'''
if @ma_sp <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_sp like ''' + replace(rtrim(@ma_sp), '''', '''''') + '%'''
if @ma_hd <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_hd like ''' + replace(rtrim(@ma_hd), '''', '''''') + '%'''
if @ma_phi <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_phi  like ''' + replace(rtrim(@ma_phi ), '''', '''''') + '%'''
if @ma_ku <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_ku like ''' + replace(rtrim(@ma_ku), '''', '''''') + '%'''

if @ma_dvcs <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_dvcs in (''' + replace(replace(replace(@ma_dvcs, ' ', ''), '''', ''''''), ',', ''',''') + ''')'
if @ds_ct <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_ct in (''' + replace(replace(replace(@ds_ct, ' ', ''), '''', ''''''), ',', ''',''') + ''')'
if @ds_ma_nt <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_nt in (''' + replace(replace(replace(@ds_ma_nt, ' ', ''), '''', ''''''), ',', ''',''') + ''')'

if @ma_kh <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_kh like ''' + replace(rtrim(@ma_kh), '''', '''''') + '%'''
if @ma_ct <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_ct like ''' + replace(rtrim(@ma_ct), '''', '''''') + '%'''
if @ma_nt <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_nt like ''' + replace(rtrim(@ma_nt), '''', '''''') + '%'''

if @tk <> '' set @queryWhereClause = @queryWhereClause + ' and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk', 'inlist', @tk)
if @tk_du <> '' set @queryWhereClause = @queryWhereClause + ' and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'inlist', @tk_du)
if @tk_kgt <> '' set @queryWhereClause = @queryWhereClause + ' and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'notinlist', @tk_kgt)

&FilterInitialize;&FilterQuery;
