      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253));
  var r = [['Tk đối ứng', 'Reference Account'], ['Tài khoản', 'Account'], ['Khách hàng', 'Customer'], ['Vụ việc', 'Job'], ['Sản phẩm', 'Product'], ['Bộ phận', 'Department'], ['Đơn vị', 'Unit']];
  var i = parseInt(a[17]), j = g._language == 'v' ? 0 : 1, subTitle = r[i][j] + ': ' + a[0];

  g._alterTitle = [null, [['%c', subTitle, true], ['%s', g._itemName, true], ['%d1', formatDateView(a[1]), true], ['%d2', formatDateView(a[2]), true]]];
  g._hiddenFields = [{Fields: 'ps_no_nt, ps_co_nt, ma_nt, ty_gia', Value: (a[14] == '10')}];
}
